mapper.select:
SELECT id
FROM `petlog`.cart
WHERE user_id = #{userId}
  AND product_id = #{productId}
  AND (
    (option_id IS NULL AND #{optionId} IS NULL)
        OR option_id = #{optionId}
    )
LIMIT 1

mapper.update:
UPDATE `petlog`.cart
SET quantity = quantity + #{additionalQuantity}
WHERE id = #{cartId}

mapper.select:
SELECT c.id AS cartId, c.product_id AS productId, c.option_id AS optionId, c.quantity, p.brand, p.name AS productName, p.price, p.discount_price AS discountPrice, p.delivery_fee AS deliveryFee, o.option_name AS optionName, o.additional_price AS additionalPrice, pi.image_url AS imageUrl FROM cart c JOIN product p ON c.product_id = p.id LEFT JOIN `option` o ON c.option_id = o.id LEFT JOIN ( SELECT product_id, image_url FROM product_image WHERE is_thumbnail = true ) pi ON p.id = pi.product_id WHERE c.id IN
#{id}
ORDER BY c.created_at DESC
